/*global QUnit*/
/**
 * test-glycoct-glygen.js
 *
 * Parametric regression tests using a curated subset of Glygen GlycoCT /
 * IUPAC condensed data.  The fixture (test/fixtures/glygen-glycoct-iupac.json)
 * was generated by scripts/generate-glygen-fixture.mjs: it contains 200
 * structures that readGlycoCT() successfully parses, stored with glycan.js's
 * own canonical IUPAC output as the reference value.
 *
 * Two test suites:
 *   1. GlycoCT → IUPAC  — parse stored GlycoCT, check .sequence matches stored iupac
 *   2. IUPAC → GlycoCT round-trip — set IupacSugar.sequence, write GlycoCT,
 *      re-parse, check round-tripped .sequence matches original
 *
 * Regenerate fixture after extending the translation table:
 *   node scripts/generate-glygen-fixture.mjs
 */

import { readGlycoCT, writeGlycoCT } from '../../js/io/glycoct.js';
import Sugar from '../../js/Sugar.js';
import { IO as Iupac } from '../../js/io/CondensedIupac.js';
import fixture from '../fixtures/glygen-glycoct-iupac.json';

class IupacSugar extends Iupac(Sugar) {}

QUnit.module('GlycoCT ↔ IUPAC (Glygen fixture)', () => {

  QUnit.test('GlycoCT → IUPAC for all fixture entries', assert => {
    let passed = 0;
    let failed = 0;

    for (const { accession, glycoct, iupac } of fixture) {
      let sugar;
      try {
        sugar = readGlycoCT(glycoct);
      } catch (e) {
        assert.ok(false, `${accession}: readGlycoCT threw: ${e.message}`);
        failed++;
        continue;
      }

      const actual = sugar.sequence;
      if (actual === iupac) {
        passed++;
      } else {
        assert.equal(actual, iupac, `${accession}: GlycoCT→IUPAC mismatch`);
        failed++;
      }
    }

    assert.ok(passed > 0, `${passed}/${fixture.length} structures passed, ${failed} failed`);
  });

  QUnit.test('IUPAC → GlycoCT round-trip for all fixture entries', assert => {
    let passed = 0;
    let failed = 0;

    for (const { accession, iupac } of fixture) {
      let roundTripped;
      try {
        const sugar  = new IupacSugar();
        sugar.sequence = iupac;
        const glycoct2 = writeGlycoCT(sugar);
        const sugar2   = readGlycoCT(glycoct2);
        roundTripped   = sugar2.sequence;
      } catch (e) {
        assert.ok(false, `${accession}: round-trip threw: ${e.message}`);
        failed++;
        continue;
      }

      if (roundTripped === iupac) {
        passed++;
      } else {
        assert.equal(roundTripped, iupac,
          `${accession}: IUPAC→GlycoCT→IUPAC round-trip mismatch`);
        failed++;
      }
    }

    assert.ok(passed > 0, `${passed}/${fixture.length} round-trips passed, ${failed} failed`);
  });

});
